import\('http'\).then\(\({ default: http }\) => {
  function req\(method, path, body\) {
    return new Promise\(\(resolve, reject\) => {
      const url = new URL\('http://localhost:3001' + path\);
      const opts = { hostname: url.hostname, port: url.port, path: url.pathname, method, headers: { 'Content-Type': 'application/json' } };
      const r = http.request\(opts, res => { let d = ''; res.on\('data', c => d += c\); res.on\('end', \(\) => resolve\({ status: res.statusCode, body: JSON.parse\(d\) }\)\); }\);
      r.on\('error', reject\);
      if \(body\) r.write\(JSON.stringify\(body\)\);
      r.end\(\);
    }\);
  }

  async function run\(\) {
    // 注入 karma_tags：2 個褪色 + 3 個現役
    const k = await req\('POST', '/api/dev/inject-karma-tags', {
      oc_name: 'PlayerA',
      karma_tags: [
        { tag: '護衛本能',   is_faded: true,  faded_at: '2026-03-01T00:00:00Z', description: '曾保護過他人的本能' },
        { tag: '迷失旅人',   is_faded: true,  faded_at: '2026-03-05T00:00:00Z', description: '曾迷失於路途的記憶' },
        { tag: '背叛的印記', is_faded: true,  faded_at: '2026-03-10T00:00:00Z', description: '曾出賣過信任之人的烙印' },
        { tag: '血腥氣息',   is_faded: false, description: '戰鬥後殘留的氣息' },
        { tag: '黑市常客',   is_faded: false, description: '熟悉地下市場的面孔' },
        { tag: '善意謊言',   is_faded: false, description: '為保護他人而說的謊' }
      ]
    }\);
    console.log\('karma_tags inject:', k.status, k.body.success ? 'OK' : k.body.error\);

    // 注入 inventory：1 個遺物
    const i = await req\('POST', '/api/dev/inject-inventory', {
      oc_name: 'PlayerA',
      inventory: [
        { item_id: 'relic_broken_flute',  type: 'relic', acquired_at: '2026-03-10T00:00:00Z' },
        { item_id: 'relic_sugar_cloak',   type: 'relic', acquired_at: '2026-03-12T00:00:00Z' }
      ]
    }\);
    console.log\('inventory inject:', i.status, i.body.success ? 'OK' : i.body.error\);

    // 驗證
    const fm = await req\('GET', '/api/user/faded-marks/PlayerA'\);
    console.log\('\\n=== 褪色印記 \(faded_marks\) ==='\);
    fm.body.faded_marks.forEach\(m => console.log\(' •', m.name, '|', m.description, '|', m.timestamp\)\);

    const rl = await req\('GET', '/api/user/relics/PlayerA'\);
    console.log\('\\n=== 遺物 \(relics\) ==='\);
    rl.body.relics.forEach\(r => console.log\(' •', r.relic_id, '|', r.name, '|', r.description\)\);
  }

  run\(\);
}\);
")

